mapper.select:
select f.reqid, f.aprvlineid, f.seq, f.approvalid, f.phase_new as phase, f.jobid, f.version, f.requesterid, f.requestername, f.regdate, f.upddate, f.reqreason, f.approverid, f.approvername ,(case when f.approvalid = 'RESTORE_APPROVAL' OR f.approvalid = 'BROWSE_APPROVAL' then (select custid from cotdl.tbl_piirestore where restoreid=f.jobid) else null end) as custid ,r.report_type, r.date_from, r.date_to, r.val1, r.val2, r.val3, DATE_FORMAT(r.apply_date,'%Y/%m/%d') as apply_date, r.apply_userid from ( select a.reqid, a.aprvlineid, a.seq, a.approvalid , (case when a.phase = 'FINAL_APPROVAL' then a.phase else b.status end) as phase_new, a.jobid, a.version , a.requesterid, a.requestername, DATE_FORMAT(a.regdate,'%Y/%m/%d %H:%i:%s') as regdate, DATE_FORMAT(b.regdate,'%Y/%m/%d %H:%i:%s') as upddate, a.reqreason , b.approverid, b.approvername from cotdl.tbl_piiapprovalreq a, cotdl.TBL_PIIAPPROVALSTEPREQ b where a.reqid = b.reqid
union all select a.reqid, a.aprvlineid, a.seq, a.approvalid , a.phase as phase_new, a.jobid, a.version , a.requesterid, a.requestername, DATE_FORMAT(a.regdate,'%Y/%m/%d %H:%i:%s') as regdate, DATE_FORMAT(a.upddate,'%Y/%m/%d %H:%i:%s') as upddate, a.reqreason , b.approverid, b.approvername from cotdl.tbl_piiapprovalreq a, cotdl.tbl_piiapprovaluser b where a.aprvlineid = b.aprvlineid and a.seq = b.seq and a.phase != 'FINAL_APPROVAL'
) as f left outer join cotdl.tbl_piireport r on f.aprvlineid = r.aprvlineid and f.jobid = r.reportid
order by reqid desc, seq desc limit #{offset}, #{amount}

select count(1) from ( select a.reqid, a.requesterid, b.approverid , (case when a.phase = 'FINAL_APPROVAL' then a.phase else b.status end) as phase_new from cotdl.tbl_piiapprovalreq a, cotdl.TBL_PIIAPPROVALSTEPREQ b where a.reqid = b.reqid
union all select a.reqid, a.requesterid, b.approverid , a.phase as phase_new from cotdl.tbl_piiapprovalreq a, cotdl.tbl_piiapprovaluser b where a.aprvlineid = b.aprvlineid and a.seq = b.seq and a.phase != 'FINAL_APPROVAL'
) as f


select exists(
	select 1
	from cotdl.tbl_piiapprovaluser b, cotdl.tbl_member m
	where b.approverid = m.userid
	  and b.aprvlineid = #{aprvlineid, jdbcType=VARCHAR}
	  and m.dept_cd = #{deptid, jdbcType=VARCHAR}
	limit 1
)
